    FIP.STM_BASE_CCY_AMT AS TRD_PCS_FEE_AMT,
    /* DRD row 232; impl=DRD_SOURCE_WITH_UNPARSED_RULE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: If TXN.SRC_STM_ID in (25, 94) - -STSR or STSR2 and FIP.FIP_TP_ID = 126 (FIPTAX03, SEC Fee) Then move STM_BASE_CCY_AMT */
    FIP.STM_BASE_CCY_AMT AS SEC_FEE_AMT,
    /* DRD row 233; impl=DRD_SOURCE_WITH_UNPARSED_RULE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: If TXN.SRC_STM_ID in (25, 94) - -STSR or STSR2 and FIP.FIP_TP_ID = 124 (FIPINT01, Accrued Interest) Then move STM_BASE_CCY_AMT */
    FIP.STM_BASE_CCY_AMT AS ACR_INT_AMT,
    /* DRD row 234; impl=DRD_SOURCE_WITH_UNPARSED_RULE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: If TXN.SRC_STM_ID in (25, 94) - -STSR or STSR2 and TXN.TXN_TP_ID in (14, 1856) - - Fund Trades and FIP.FIP_TP_ID in (123, 160) - -FIPCOM01, FIPCOM91 Then move STM_BASE_CCY_AMT */
    FIP.STM_BASE_CCY_AMT AS CNCSN_AMT,
    /* DRD row 235; impl=DRD_AVY_FIP_CASE_COMPILED; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: If TXN.SRC_STM_ID in (25, 94) - -STSR or STSR2 and TXN.TXN_TP_ID in (14, 1856) - - Fund Trades and TXN.BUY_SELL_IND = 'Sell' and FIP.FIP_TP_ID = 132 (FIPFEE02, Miscellaneous Fee(s)) Then for TXN.SRC_STM_ID = 94 move STM_BASE_CCY_AMT for TXN.SRC_STM_ID = 25 move OTHR_FEE */
    CASE WHEN TXN.SRC_STM_ID IN (25, 94) AND TXN.TXN_TP_ID IN (14, 1856) AND TXN.BUY_SELL_IND = 'Sell' AND FIP.FIP_TP_ID = 132 THEN CASE WHEN TXN.SRC_STM_ID = 94 THEN FIP.STM_BASE_CCY_AMT WHEN TXN.SRC_STM_ID = 25 THEN FIP.OTHR_FEE END END AS CDSC_AMT,
    /* DRD row 236; impl=DRD_AVY_FIP_CASE_COMPILED; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: If TXN.SRC_STM_ID in (25, 94) - -STSR or STSR2 and FIP.FIP_TP_ID = 132 (FIPFEE02, Miscellaneous Fee(s)) Then for TXN.SRC_STM_ID = 94 move STM_BASE_CCY_AMT for TXN.SRC_STM_ID = 25 move OTHR_FEE */
    CASE WHEN TXN.SRC_STM_ID IN (25, 94) AND FIP.FIP_TP_ID = 132 THEN CASE WHEN TXN.SRC_STM_ID = 94 THEN FIP.STM_BASE_CCY_AMT WHEN TXN.SRC_STM_ID = 25 THEN FIP.OTHR_FEE END END AS OTHR_FEE_AMT,
    /* DRD row 237; impl=DRD_AVY_EXISTS_COMPILED; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: If there is a record in CCAL_REPL_OWNER.TXN_RLTNP table with TXN.TXN_ID = TXN_RLTNP.TRGT_TXN_ID and TXN_RLTNP_TP_ID = 69 (Cancel) and TXN_RLTNP.TRGT_TXN_ID <> TXN_RLTNP.SRC_TXN_ID then set to 'Y' for both TRGT_TXN_ID and SRC_TXN_ID. The check should be performed each time when a new record is written into CCAL_REPL_OWNER.TXN_RLTNP with TXN_RLTNP_TP_ID = 69 and update the flag for both TRGT_TXN_ID and SRC_TXN_ID, if TXN_RLTNP.TRGT_TXN_ID <> TXN_RLTNP.SRC_TXN_ID. Note: TXN_RLTNP.TRGT_TXN_ID <> TXN_RLTNP.SRC_TXN_ID is needed because it is possible that cancellation trade points to itself when the original trade that is being cancelled is not found. In this case Cancelled Flag should not be set to 'Y' */
    CASE WHEN EXISTS (SELECT 1 FROM CCAL_REPL_OWNER.TXN_RLTNP WHERE TXN_RLTNP.TXN_RLTNP_TP_ID = 69 AND TXN_RLTNP.TRGT_TXN_ID <> TXN_RLTNP.SRC_TXN_ID AND (TXN_RLTNP.TRGT_TXN_ID = TXN.TXN_ID OR TXN_RLTNP.SRC_TXN_ID = TXN.TXN_ID)) THEN 'Y' END AS TRD_CNCLD_F,
    /* DRD row 238; impl=DRD_AVY_ETL_NOTES_SOURCE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Use APASEC and Product Information logic from 'ETL Notes' tab. Product Information: (Security source CUSIP, Security Product Id, Security CIRD Product Id, Security Option Symbol, Symbol, ISIN, Product Composite Description, Product Short Name, Product Description) If there is atleast 1 APASEC, consider above fields from that APASEC If there is an iAPASEC but no APASEC, consider above fields from iAPASEC */
    SEC_APA.SYMB AS SYMB,
    /* DRD row 239; impl=DRD_AVY_ETL_NOTES_SOURCE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Use APASEC and Product Information logic from 'ETL Notes' tab. Product Information: (Security source CUSIP, Security Product Id, Security CIRD Product Id, Security Option Symbol, Symbol, ISIN, Product Composite Description, Product Short Name, Product Description) If there is atleast 1 APASEC, consider above fields from that APASEC If there is an iAPASEC but no APASEC, consider above fields from iAPASEC */
    SEC_APA.ISIN AS ISIN,
    /* DRD row 240; impl=DRD_SOURCE_REQUIRES_JOIN; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Left join to CCAL_REPL_OWNER.TXN_SRC_TAX_CODE_LKUP LKP table on TXN.SRC_TAX_CODE_ID = LKP.SRC_TAX_CODE_ID and LKP.ACTV_F = 'Y' */
    TXN_SRC_TAX_CODE_LKUP.SRC_TAX_CODE AS TXN_SRC_TAX_CD,
    /* DRD row 241; impl=DRD_SOURCE_REQUIRES_JOIN; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Left join to CCAL_REPL_OWNER.TXN_SRC_TAX_CODE_LKUP LKP table on TXN.SRC_TAX_CODE_ID = LKP.SRC_TAX_CODE_ID and LKP.ACTV_F = 'Y' */
    TXN_SRC_TAX_CODE_LKUP.SRC_TAX_CODE_DSC AS TXN_SRC_TAX_CD_DSC,
    /* DRD row 242; impl=DRD_DIRECT_SOURCE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    NULL AS TM_PRC_DISCRETION_F,
    /* DRD row 243; impl=DRD_AVY_ETL_NOTES_SOURCE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Use APACSH logic from 'ETL Notes' tab and below logic: ccal_repl_owner.txn t join ccal_repl_owner.apa ap ON ap.exec_id = t.txn_id left join ccal_repl_owner.txn_avy_cl tac ON tac.txn_id = t.txn_id and tac.actv_f = 'Y' and ap.apa_id = tac.apa_id left join ccal_repl_owner.avy_cl acl ON acl.avy_cl_id = tac.avy_cl_id */
    CASH_TXN_AVY_CL.NNA_CGY_ID AS CASH_NNA_CGY_ID,
    /* DRD row 244; impl=DRD_AVY_ETL_NOTES_SOURCE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Use APACSH logic from 'ETL Notes' tab and below logic: ccal_repl_owner.txn t join ccal_repl_owner.apa ap ON ap.exec_id = t.txn_id left join ccal_repl_owner.txn_avy_cl tac ON tac.txn_id = t.txn_id and tac.actv_f = 'Y' and ap.apa_id = tac.apa_id left join ccal_repl_owner.net_new _ast_cgy nna ON nna.net_new_ast_cgy_id = tac.net_new_ast_cgy_id */
    CASH_NNA_CGY.NNA_CGY_NM AS CASH_NNA_CGY_NM,
    /* DRD row 245; impl=DRD_AVY_ETL_NOTES_SOURCE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Use APASEC logic from 'ETL Notes' tab and below logic: ccal_repl_owner.txn t join ccal_repl_owner.apa ap ON ap.exec_id = t.txn_id left join ccal_repl_owner.txn_avy_cl tac ON tac.txn_id = t.txn_id and tac.actv_f = 'Y' and ap.apa_id = tac.apa_id left join ccal_repl_owner.avy_cl acl ON acl.avy_cl_id = tac.avy_cl_id */
    SEC_TXN_AVY_CL.NNA_CGY_ID AS SCR_NNA_CGY_ID,
    /* DRD row 246; impl=DRD_AVY_ETL_NOTES_SOURCE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Use APASEC logic from 'ETL Notes' tab and below logic: ccal_repl_owner.txn t join ccal_repl_owner.apa ap ON ap.exec_id = t.txn_id left join ccal_repl_owner.txn_avy_cl tac ON tac.txn_id = t.txn_id and tac.actv_f = 'Y' and ap.apa_id = tac.apa_id left join ccal_repl_owner.net_new _ast_cgy nna ON nna.net_new_ast_cgy_id = tac.net_new_ast_cgy_id */
    SEC_NNA_CGY.NNA_CGY_NM AS SCR_NNA_CGY_NM,
    /* DRD row 247; impl=DRD_SOURCE_WITH_UNPARSED_RULE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: value to be picked from APASEC */
    APA.YIELD AS YLD,
    /* DRD row 248; impl=DRD_SOURCE_WITH_UNPARSED_RULE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: value to be picked from APASEC */
    APA.YIELD_TO_WORST AS YTW,
    /* DRD row 249; impl=DRD_SOURCE_WITH_UNPARSED_RULE; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: value to be picked from APASEC */
    APA.YIELD_TO_WORST_CD AS YTW_CD,
    /* DRD row 250; impl=DRD_SOURCE_REQUIRES_JOIN; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: JOIN ccal_repl_owner.txn t with ccal_repl_owner.Apa ap on ap.exec_id = t.txn_id JOIN ccsi_owner.ar_grp_subdim ar_grp_subdim ON ar_grp_subdim.ar_id = t.ar_id AND t.td >= ar_grp_subdim.eff_dt AND t.td < ar_grp_subdim.end_dt join ccsi_owner.ar_dim bkr_ar_dim on ar_grp_subdim.linked_bkr_ar_id = bkr_ar_dim.ar_id AND t.td >= ar_dim.eff_dt AND t.td < ar_dim.end_dt */
    AR_DIM.ORIG_SRC_STM_AR_ID AS BKR_AC_NUM,
