    /* DRD rule: ccal_repl_owner.cl_val cv left join ccal_repl_owner.cl_val cv ON cv.cl_val_id = t.SRC_BUY_SELL_MULTI_ID and cv.CL_SCM_ID = '99' (this is excessive; using cl_val_id no need to use CL_SCM. Added for consistency with existing Name attribute) */
    SIS_DLTD_EV_CD_CL_VAL.CL_VAL_CODE AS SIS_DLTD_EV_CD,
    /* DRD row 252; impl=DRD_AVY_CASE_COMPILED; compare=REVIEW_REQUIRED; reason=Missing source-system condition */
    /* DRD rule: For TXN.SRC_STM_ID = 60 (ACTDETTD), use ORIG_TD. Suppress from Original Trade Date for ACTDETTD source */
    CASE WHEN TXN.SRC_STM_ID = 60 THEN TXN.ORIG_TD END AS DB_CARD_TXN_DT,
    /* DRD row 253; impl=DRD_AVY_CASE_COMPILED; compare=REVIEW_REQUIRED; reason=Missing source-system condition */
    /* DRD rule: Only applicable to SRC_STM_ID = 60 (ACTDETTD) ccal_repl_owner.txn t join ccal_repl_owner.apa ap ON ap.exec_id = t.txn_id join REFERENCE_repl_OWNER.CCY orig on apa.orig_ccy_id = orig.CCY_ISO_NUM_CODE TBC if CDS values are to be left padded with 0 to 3 */
    CASE WHEN TXN.SRC_STM_ID = 60 THEN CCY.CCY_CODE END AS DB_CARD_ORIG_CCY_CD,
    /* DRD row 254; impl=DRD_SOURCE_REQUIRES_JOIN; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: Only applicable to SRC_STM_ID = 60 (ACTDETTD) ccal_repl_owner.txn t join ccal_repl_owner.apa ap ON ap.exec_id = t.txn_id join REFERENCE_repl_OWNER.CCY orig on apa.orig_ccy_id = orig.CCY_ISO_NUM_CODE */
    CCY.CCY_NM AS DB_CARD_ORIG_CCY,
    /* DRD row 255; impl=DRD_AVY_PARSE_TYPE_CODE_COMPILED; compare=REVIEW_REQUIRED; reason=Possible wrong lookup / missing parse */
    /* DRD rule: For TXN.SRC_STM_ID = 60 (ACTDETTD), use TRADE_NUMBER. Parse to extract SDIRA Transaction Type. For example, from "02726" value it will be "027", while 26 stands for 2026 year. Lookup CL_VAL_CODE (does not exist today) Suppress from Trade Date for ACTDETTD source */
    CASE WHEN TXN.SRC_STM_ID = 60 THEN SUBSTR(TXN.TRD_NUM, 1, 3) END AS SDIRA_TXN_TP_CD,
    /* DRD row 256; impl=DRD_AVY_PARSE_CL_VAL_LOOKUP_COMPILED; compare=REVIEW_REQUIRED; reason=Possible wrong lookup / missing parse */
    /* DRD rule: For TXN.SRC_STM_ID = 60 (ACTDETTD), use TRADE_NUMBER. Parse to extract SDIRA Transaction Type. For example, from "02726" value it will be "027", while 26 stands for 2026 year. Lookup CL_VAL_CODE (does not exist today) */
    CASE WHEN TXN.SRC_STM_ID = 60 THEN SDIRA_TXN_TP_CL_VAL.CL_VAL_NM END AS SDIRA_TXN_TP,
    /* DRD row 257; impl=DRD_AVY_PARSE_COMPILED; compare=REVIEW_REQUIRED; reason=Possible wrong lookup / missing parse */
    /* DRD rule: For TXN.SRC_STM_ID = 60 (ACTDETTD), use TRADE_NUMBER. Parse to extract SDIRA Transaction Year (last two digits) and add century part. For example, from "02726" value it will be "027" for SDIRA Transaction Type, while 26 stands for 2026 year. */
    CASE WHEN TXN.SRC_STM_ID = 60 THEN 2000 + TO_NUMBER(SUBSTR(TXN.TRD_NUM, -2)) END AS SDIRA_TXN_YR,
    /* DRD row 258; impl=DRD_SOURCE_REQUIRES_JOIN; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: ccal_repl_owner.txn t join ccal_repl_owner.apa ap ON ap.exec_id = t.txn_id join REFERENCE_repl_OWNER.CCY txn on apa.txn_iso_ccy_code = txn.CCY_CODE */
    CCY.CCY_NM AS TXN_CCY,
    /* DRD row 259; impl=DRD_SOURCE_REQUIRES_JOIN; compare=IN_BOTH_NO_REVIEW; reason=IN_BOTH */
    /* DRD rule: ( nvl(ar_dim .ira_f, 'N') ) JOIN ccal_repl_owner.txn t with ccal_repl_owner.Apa ap on ap.exec_id = t.txn_id JOIN ccsi_owner.ar_grp_subdim ar_grp_subdim ON ar_grp_subdim.ar_id = t.ar_id AND t.td >= ar_grp_subdim.eff_dt AND t.td < ar_grp_subdim.end_dt join ccsi_owner.ar_dim bkr_ar_dim on ar_grp_subdim.linked_bkr_ar_id = bkr_ar_dim.ar_id AND t.td >= ar_dim.eff_dt AND t.td < ar_dim.end_dt */
    AR_DIM.IRA_F AS BKR_IRA_F,
