    /* DRD rule: ( nvl(ar_dim .ERISSA_F, 'N') ) JOIN ccal_repl_owner.txn t with ccal_repl_owner.Apa ap on ap.exec_id = t.txn_id JOIN ccsi_owner.ar_grp_subdim ar_grp_subdim ON ar_grp_subdim.ar_id = t.ar_id AND t.td >= ar_grp_subdim.eff_dt AND t.td < ar_grp_subdim.end_dt join ccsi_owner.ar_dim bkr_ar_dim on ar_grp_subdim.linked_bkr_ar_id = bkr_ar_dim.ar_id AND t.td >= ar_dim.eff_dt AND t.td < ar_dim.end_dt */
    AR_DIM.ERISSA_F AS BKR_ERISA_F,
