    /* DRD rule: JOIN ccal_repl_owner.txn t with ccal_repl_owner.Apa ap on ap.exec_id = t.txn_id JOIN ccal_repl_owner.ccal_cird_pd_map ccal_cird_pd_map on ON ap.pd_id = ccal_cird_pd_map.ccal_pd_id ND ccal_cird_pd_map.actv_f = 'Y' JOIN cird_owner.imt_pd_dim imt_pd_dim1 on ap.pd_id = imt_pd_dim1.cird_pd_id (- - cird_pd-based dimension (only used when src_stm_id = 93)) AND t.td >= imt_pd_dim1.eff_dt AND t.td < imt_pd_dim1.end_dt JOIN cird_owner.imt_pd_dim imt_pd_dim ON ap.pd_id = imt_pd_dim.ccal_pd_id (ccal_pd-based dimension) AND t.td >= imt_pd_dim.eff_dt AND t.td < imt_pd_dim.end_dt JOIN cird_owner.imt_pd_dim imt_pd_dim_cird ON ccal_cird_pd_map.cird_pd_id = imt_pd_dim_cird.cird_pd_id (Dimension via mapped cird_pd) AND t.td >= imt_pd_dim_cird.eff_dt AND t.td < imt_pd_dim_cird.end_dt; */
