    /* DRD rule: Fetch FA_NUMBER_V.FA_NUMBER_TYPE_CODE As OWN_FA_NUM_TP_CD LEFT Join with CCAL_REPL_OWNER.TXN TXN With CCSI_OWNER.AR_GRP_SUBDIM AR_GRP_SUBDIM ON TXN.AR_ID = AR_GRP_SUBDIM.AR_ID And TXN.TD >= AR_GRP_SUBDIM.EFF_DT And TXN.TD < AR_GRP_SUBDIM.END_DT Left Join SSDS_DAL_OWNER.FA_NUMBER_V FA_NUMBER_V ON AR_GRP_SUBDIM.FA_NUM = FA_NUMBER_V.FA_NUMBER And TXN.TD >= FA_NUMBER_V.EFFECTIVE_DATE And TXN.TD < FA_NUMBER_V.END_DATE */
