    LEFT JOIN CCAL_REPL_OWNER.CL_VAL SRC_CNCL_RSN_NM_CL_VAL ON SRC_CNCL_RSN_NM_CL_VAL.CL_VAL_ID = TXN.SRC_CNCL_RSN_ID AND SRC_CNCL_RSN_NM_CL_VAL.CL_SCM_ID = 102 /* DRD_CL_VAL_LOOKUP; cols=SRC_CNCL_RSN_NM */
