    LEFT JOIN CCAL_REPL_OWNER.NNA_CGY CASH_NNA_CGY ON CASH_NNA_CGY.NNA_CGY_ID = CASH_TXN_AVY_CL.NNA_CGY_ID /* DRD_ETL_NOTES_APACSH; cols=CASH_NNA_CGY_NM */
