    JOIN CCSI_OWNER.AR_DIM AR_DIM_4 ON ar_grp_subdim.linked_bkr_ar_id = AR_DIM_4.ar_id AND TXN.td >= AR_DIM_4.eff_dt AND TXN.td < AR_DIM_4.end_dt /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_D...; cols=BKR_ABC_CLSS | BKR_ABC_CLSS_CD | BKR_AC_CGY | BKR_AC_CGY_CD | BKR_AC_NUM | BKR_AC_OWNSHP_TP | BKR_AC_OWNSHP_TP_CD | BKR_BSN_LINE_AFFLT | BKR_BSN_LINE_AFFLT_CD | BKR_ERISA_F | BKR_FEE_BASE_AC_F | BKR_FIRM_AC_F | BKR_IRA_F | BKR_ORIG_SRC_STM_CD | BKR_RJ_BSN_UNIT | BKR_RJ_BSN_UNIT_CD | BKR_RJ_TAX_RPT_RSPL_F | BKR_RJ_TRUST_F | BKR_TAX_AC_F | BKR_TAX_RPT_CLNT_ID | BKR_TST_AC_F */
    LEFT JOIN CCAL_REPL_OWNER.CL_VAL SIS_DLTD_EV_CD_CL_VAL ON SIS_DLTD_EV_CD_CL_VAL.CL_VAL_ID = TXN.SRC_BUY_SELL_MULTI_ID AND SIS_DLTD_EV_CD_CL_VAL.CL_SCM_ID = 99 /* DRD_CL_VAL_LOOKUP; cols=SIS_DLTD_EV_CD */
    JOIN REFERENCE_REPL_OWNER.CCY CCY ON apa.orig_ccy_id = CCY.CCY_ISO_NUM_CODE /* /* TBC */ */ /* DRD_AD_RULE+CANONICAL_ALIAS; cols=DB_CARD_ORIG_CCY_CD */
    LEFT JOIN REFERENCE_REPL_OWNER.CCY CCY_2 ON APA.ORIG_CCY_ID = CCY_2.CCY_ISO_NUM_CODE /* AVY_CURATED_DRD_JOIN+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+ALIAS_DEDUP; cols=DB_CARD_ORIG_CCY | DB_CARD_ORIG_CCY_CD */
    JOIN REFERENCE_REPL_OWNER.CCY CCY_3 ON apa.txn_iso_ccy_code = CCY_3.CCY_CODE /* DRD_AD_RULE+CANONICAL_ALIAS+ALIAS_DEDUP; cols=TXN_CCY */
    JOIN CCSI_OWNER.AR_DIM AR_DIM_5 ON TXN.ar_id = AR_DIM_5.ar_id AND TXN.td >= AR_DIM_5.eff_dt AND TXN.td < AR_DIM_5.end_dt /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+ALIAS_DEDUP; cols=AC_CGY | AC_CGY_CD | AC_OWNSHP_TP | AC_OWNSHP_TP_CD | RJ_BSN_UNIT | RJ_BSN_UNIT_CD | TAX_AC_F | TAX_RPT_CLNT_ID | TST_AC_F */
    JOIN CCSI_OWNER.AR_DIM BKR_AR_DIM_3 ON ar_grp_subdim.linked_bkr_ar_id = BKR_AR_DIM_3.ar_id AND TXN.td >= ar_dim.eff_dt AND TXN.td < ar_dim.end_dt /* DRD_AD_RULE+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+ME...; cols=OWN_FA_CRN_ADV_F | OWN_FA_CSS_PSN_ID | OWN_FA_DEPT_BR_CD | OWN_FA_DSCR_F | OWN_FA_DSCR_ST | OWN_FA_DSCR_ST_CD | OWN_FA_ENT_BR_CD | OWN_FA_ENT_BSN_OPN_DT | OWN_FA_ENT_BSN_ST | OWN_FA_ENT_CSS_ID | OWN_FA_ENT_DIV_CD | OWN_FA_ENT_DIV_DSC | OWN_FA_ENT_DIV_NODE | OWN_FA_ENT_LOB_AB_F | OWN_FA_ENT_LOB_AMS_F | OWN_FA_ENT_LOB_BSN_MODL | OWN_FA_ENT_LONG_CD | OWN_FA_ENT_MAIN_BR_STE | OWN_FA_ENT_OSJ | OWN_FA_ENT_RJAS_ID_F | OWN_FA_ENT_RSK_HIER_BSN_UNIT_CD | OWN_FA_ENT_RSK_HIER_BSN_UNIT_DSC | OWN_FA_ENT_RT... */
    JOIN SSDS_DAL_OWNER.FA_NUMBER_V FA_NUMBER_V_2 ON UPPER(TRIM(bkr_ar_dim.own_bsn_ent_cd)) = FA_NUMBER_V_2.fa_number AND TXN.td >= FA_NUMBER_V_2.effective_date AND TXN.td < FA_NUMBER_V_2.end_date /* DRD_AD_RULE+CANONICAL_ALIAS+ALIAS_DEDUP; cols=OWN_PRIM_FA_NUM */
    JOIN SSDS_DAL_OWNER.FA_NUMBER_V FA_NUMBER_V_3 ON FA_NUMBER_V_3.responsible_party_employee_id = fa_number_v1.responsible_party_employee_id and FA_NUMBER_V_3.fa_number_type_code in ('pri','PRI') AND TXN.td >= FA_NUMBER_V_3.effective_date AND TXN.td < FA_NUMBER_V_3.end_date /* DRD_AD_RULE+CANONICAL_ALIAS+ALIAS_DEDUP; cols=OWN_PRIM_FA_NUM */
    LEFT JOIN SSDS_DAL_OWNER.PERSON_RV PERSON_RV ON PERSON_RV.EMPLOYEE_ID = FA_NUMBER_V1.RESPONSIBLE_PARTY_EMPLOYEE_ID AND TXN.TD >= PERSON_RV.EFFECTIVE_DATE AND TXN.TD < PERSON_RV.END_DATE /* DRD_AVY_INFERRED_JOIN+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP; cols=OWN_FA_CSS_PSN_ID | OWN_FA_DEPT_BR_CD | OWN_FA_FINRA_CRD_CLSS_CD | OWN_FA_HR_ST_CD | OWN_FA_PRODUCER_F */
    JOIN SSDS_DAL_OWNER.FA_NUMBER_V FA_NUMBER_V1 ON UPPER(TRIM(bkr_ar_dim.own_bsn_ent_cd)) = fa_number_v1.fa_number AND TXN.td >= fa_number_v1.effective_date AND TXN.td < fa_number_v1.end_date /* DRD_AD_RULE+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+ME...; cols=OWN_FA_CRN_ADV_F | OWN_FA_CSS_PSN_ID | OWN_FA_DEPT_BR_CD | OWN_FA_DSCR_F | OWN_FA_DSCR_ST | OWN_FA_DSCR_ST_CD | OWN_FA_ENT_BR_CD | OWN_FA_ENT_BSN_OPN_DT | OWN_FA_ENT_BSN_ST | OWN_FA_ENT_CSS_ID | OWN_FA_ENT_DIV_CD | OWN_FA_ENT_DIV_DSC | OWN_FA_ENT_DIV_NODE | OWN_FA_ENT_LOB_AB_F | OWN_FA_ENT_LOB_AMS_F | OWN_FA_ENT_LOB_BSN_MODL | OWN_FA_ENT_LONG_CD | OWN_FA_ENT_MAIN_BR_STE | OWN_FA_ENT_OSJ | OWN_FA_ENT_RJAS_ID_F | OWN_FA_ENT_RSK_HIER_BSN_UNIT_CD | OWN_FA_ENT_RSK_HIER_BSN_UNIT_DSC | OWN_FA_ENT_RT... */
    JOIN SSDS_DAL_OWNER.PERSON_BROKERAGE_SUBDIMENSION_V PERSON_BROKERAGE_SUBDIMENSION_V ON PERSON_BROKERAGE_SUBDIMENSION_V.EMPLOYEE_ID = fa_number_v1.responsible_party_employee_id AND TXN.td >= PERSON_BROKERAGE_SUBDIMENSION_V.effective_date AND TXN.td < PERSON_BROKERAGE_SUBDIMENSION_V.end_date /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP; cols=OWN_FA_CRN_ADV_F | OWN_FA_QUALF_ADV_F */
    JOIN SSDS_DAL_OWNER.PERSON_AMS_DISCRETIONARY_STATUS_V PERSON_AMS_DISCRETIONARY_STATUS_V ON PERSON_AMS_DISCRETIONARY_STATUS_V.EMPLOYEE_ID = fa_number_v1.responsible_party_employee_id AND TXN.td >= PERSON_AMS_DISCRETIONARY_STATUS_V.effective_date AND TXN.td < PERSON_AMS_DISCRETIONARY_STATUS_V.end_date /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP; cols=OWN_FA_DSCR_F | OWN_FA_DSCR_ST | OWN_FA_DSCR_ST_CD */
    JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V ENTERPRISE_ENTITY_DIM_V_2 ON ENTERPRISE_ENTITY_DIM_V_2.entity_code_long = fa_number_v1.fa_number_entity_code AND TXN.td >= ENTERPRISE_ENTITY_DIM_V_2.effective_date AND TXN.td < ENTERPRISE_ENTITY_DIM_V_2.end_date AND ENTERPRISE_ENTITY_DIM_V_2.entity_recycled_boolean = 0 AND ENTERPRISE_ENTITY_DIM_V_2.entity_financial_ria_boolean = 0 /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_D...; cols=OWN_FA_ENT_BR_CD | OWN_FA_ENT_BSN_OPN_DT | OWN_FA_ENT_BSN_ST | OWN_FA_ENT_CSS_ID | OWN_FA_ENT_DIV_CD | OWN_FA_ENT_DIV_DSC | OWN_FA_ENT_DIV_NODE | OWN_FA_ENT_LOB_AB_F | OWN_FA_ENT_LOB_AMS_F | OWN_FA_ENT_LOB_BSN_MODL | OWN_FA_ENT_LONG_CD | OWN_FA_ENT_MAIN_BR_STE | OWN_FA_ENT_OSJ | OWN_FA_ENT_RJAS_ID_F | OWN_FA_ENT_SBTP | OWN_FA_ENT_SBTP_CD | OWN_FA_ENT_SHRT_CD | OWN_FA_ENT_SUBDIV_CD | OWN_FA_ENT_SUBDIV_DSC | OWN_FA_ENT_SUBS | OWN_FA_ENT_TP | OWN_FA_ENT_TP_CD */
    JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V OWN_FA_ENT ON own_fa_ent.entity_code_long = fa_number_v1.fa_number_entity_code AND TXN.td >= own_fa_ent.effective_date AND TXN.td < own_fa_ent.end_date AND own_fa_ent.entity_recycled_boolean = 0 AND own_fa_ent.entity_financial_ria_boolean = 0 /* DRD_AD_RULE+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP; cols=OWN_FA_ENT_RTL_HIER_BSN_MODL_CD | OWN_FA_ENT_RTL_HIER_BSN_MODL_DSC | OWN_FA_ENT_RTL_HIER_RPT_UNIT_CD | OWN_FA_ENT_RTL_HIER_RPT_UNIT_DSC | OWN_FA_ENT_RTL_HIER_TERR_CD | OWN_FA_ENT_RTL_HIER_TERR_DSC | OWN_FA_ENT_RTL_SALE_CPX_CD | OWN_FA_ENT_RTL_SALE_DIV_CD | OWN_FA_ENT_RTL_SALE_HIER_LOB_CD | OWN_FA_ENT_RTL_SALE_HIER_LOB_DSC | OWN_FA_ENT_RTL_SALE_HIER_RGON_CD | OWN_FA_ENT_RTL_SALE_HIER_RGON_DSC */
    JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RETAIL_DIMENSION_V ENTERPRISE_ENTITY_RETAIL_DIMENSION_V ON ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.entity_enterprise_id = own_fa_ent.entity_enterprise_id AND TXN.td >= ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.effective_date AND TXN.td < ENTERPRISE_ENTITY_RETAIL_DIMENSION_V.end_date /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP; cols=OWN_FA_ENT_RTL_HIER_BSN_MODL_CD | OWN_FA_ENT_RTL_HIER_BSN_MODL_DSC | OWN_FA_ENT_RTL_HIER_RPT_UNIT_CD | OWN_FA_ENT_RTL_HIER_RPT_UNIT_DSC | OWN_FA_ENT_RTL_HIER_TERR_CD | OWN_FA_ENT_RTL_HIER_TERR_DSC | OWN_FA_ENT_RTL_SALE_CPX_CD | OWN_FA_ENT_RTL_SALE_DIV_CD | OWN_FA_ENT_RTL_SALE_HIER_LOB_CD | OWN_FA_ENT_RTL_SALE_HIER_LOB_DSC | OWN_FA_ENT_RTL_SALE_HIER_RGON_CD | OWN_FA_ENT_RTL_SALE_HIER_RGON_DSC */
    LEFT JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RISK_DIM ENTERPRISE_ENTITY_RISK_DIM ON ENTERPRISE_ENTITY_RISK_DIM.ENTITY_ENTERPRISE_ID = OWN_FA_ENT.ENTITY_ENTERPRISE_ID AND TXN.TD >= ENTERPRISE_ENTITY_RISK_DIM.EFFECTIVE_DATE AND TXN.TD < ENTERPRISE_ENTITY_RISK_DIM.END_DATE /* DRD_AVY_INFERRED_JOIN+MERGED_DUP; cols=OWN_FA_ENT_RSK_HIER_BSN_UNIT_CD | OWN_FA_ENT_RSK_HIER_BSN_UNIT_DSC */
    JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_DIM_V OWN_FA_ENT_2 ON OWN_FA_ENT_2.entity_code_long = fa_number_v1.fa_number_entity_code AND TXN.td >= OWN_FA_ENT_2.effective_date AND TXN.td < OWN_FA_ENT_2.end_date AND OWN_FA_ENT_2.entity_recycled_boolean = 0 AND OWN_FA_ENT_2.entity_financial_ria_boolean = 0 /* DRD_AD_RULE+MERGED_DUP+ALIAS_DEDUP; cols=OWN_FA_ENT_RSK_HIER_BSN_UNIT_CD | OWN_FA_ENT_RSK_HIER_BSN_UNIT_DSC */
    JOIN SSDS_DAL_OWNER.ENTERPRISE_ENTITY_RISK_DIMENSION_V OWN_RISK_ENT ON own_fa_ent.entity_enterprise_id = own_risk_ent.entity_enterprise_id AND TXN.td >= own_risk_ent.effective_date AND TXN.td < own_risk_ent.end_date /* DRD_AD_RULE+MERGED_DUP; cols=OWN_FA_ENT_RSK_HIER_BSN_UNIT_CD | OWN_FA_ENT_RSK_HIER_BSN_UNIT_DSC */
    JOIN CCAL_REPL_OWNER.CCAL_CIRD_PD_MAP CCAL_CIRD_PD_MAP_2 ON ON APA.pd_id = CCAL_CIRD_PD_MAP_2.ccal_pd_id AND CCAL_CIRD_PD_MAP_2.actv_f = 'Y' /* DRD_AD_RULE+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+ME...; cols=EQTY_IDY | EQTY_IDY_CD | EQTY_IDY_GRP | EQTY_IDY_GRP_CD | EQTY_SECT | EQTY_SECT_CD | EQTY_SUP_SECT | EQTY_SUP_SECT_CD | FND_FAM | IMT_CL_LVL_1 | IMT_CL_LVL_1_CD | IMT_CL_LVL_2 | IMT_CL_LVL_2_CD | IMT_CL_LVL_3 | IMT_CL_LVL_3_CD | IMT_CL_LVL_4 | IMT_CL_LVL_4_CD | IMT_CL_LVL_5 | IMT_CL_LVL_5_CD | MODL_STRTG_DTL_AST_CLSS | MODL_STRTG_DTL_AST_CLSS_CD | MODL_STRTG_SMY_AST_CLSS | MODL_STRTG_SMY_AST_CLSS_CD | PD_DSC | PD_SHRT_NM | RPT_CL_LVL_1 | RPT_CL_LVL_2 | RPT_STRTG_DTL_AST_CLSS | RPT_STRTG_DTL_A... */
    JOIN CIRD_OWNER.IMT_PD_DIM IMT_PD_DIM ON APA.pd_id = IMT_PD_DIM.cird_pd_id /* cird_pd-based dimension /* only used AND src_stm_id = 93 * / */ AND TXN.td >= IMT_PD_DIM.eff_dt AND TXN.td < IMT_PD_DIM.end_dt /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_D...; cols=EQTY_IDY | EQTY_IDY_CD | EQTY_IDY_GRP | EQTY_IDY_GRP_CD | EQTY_SECT | EQTY_SECT_CD | EQTY_SUP_SECT | EQTY_SUP_SECT_CD | FND_FAM | IMT_CL_LVL_1 | IMT_CL_LVL_1_CD | IMT_CL_LVL_2 | IMT_CL_LVL_2_CD | IMT_CL_LVL_3 | IMT_CL_LVL_3_CD | IMT_CL_LVL_4 | IMT_CL_LVL_4_CD | IMT_CL_LVL_5 | IMT_CL_LVL_5_CD | MODL_STRTG_DTL_AST_CLSS | MODL_STRTG_DTL_AST_CLSS_CD | MODL_STRTG_SMY_AST_CLSS | MODL_STRTG_SMY_AST_CLSS_CD | PD_DSC | PD_SHRT_NM | RPT_CL_LVL_1 | RPT_CL_LVL_2 | RPT_STRTG_DTL_AST_CLSS | RPT_STRTG_DTL_A... */
    JOIN CIRD_OWNER.IMT_PD_DIM IMT_PD_DIM_2 ON APA.pd_id = IMT_PD_DIM_2.ccal_pd_id /* ccal_pd-based dimension */ AND TXN.td >= IMT_PD_DIM_2.eff_dt AND TXN.td < IMT_PD_DIM_2.end_dt /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_D...; cols=EQTY_IDY | EQTY_IDY_CD | EQTY_IDY_GRP | EQTY_IDY_GRP_CD | EQTY_SECT | EQTY_SECT_CD | EQTY_SUP_SECT | EQTY_SUP_SECT_CD | FND_FAM | IMT_CL_LVL_1 | IMT_CL_LVL_1_CD | IMT_CL_LVL_2 | IMT_CL_LVL_2_CD | IMT_CL_LVL_3 | IMT_CL_LVL_3_CD | IMT_CL_LVL_4 | IMT_CL_LVL_4_CD | IMT_CL_LVL_5 | IMT_CL_LVL_5_CD | MODL_STRTG_DTL_AST_CLSS | MODL_STRTG_DTL_AST_CLSS_CD | MODL_STRTG_SMY_AST_CLSS | MODL_STRTG_SMY_AST_CLSS_CD | PD_DSC | PD_SHRT_NM | RPT_CL_LVL_1 | RPT_CL_LVL_2 | RPT_STRTG_DTL_AST_CLSS | RPT_STRTG_DTL_A... */
    JOIN CIRD_OWNER.IMT_PD_DIM IMT_PD_DIM_3 ON ccal_cird_pd_map.cird_pd_id = IMT_PD_DIM_3.cird_pd_id /* Dimension via mapped cird_pd */ AND TXN.td >= IMT_PD_DIM_3.eff_dt AND TXN.td < IMT_PD_DIM_3.end_dt /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_DUP+MERGED_D...; cols=EQTY_IDY | EQTY_IDY_CD | EQTY_IDY_GRP | EQTY_IDY_GRP_CD | EQTY_SECT | EQTY_SECT_CD | EQTY_SUP_SECT | EQTY_SUP_SECT_CD | FND_FAM | IMT_CL_LVL_1 | IMT_CL_LVL_1_CD | IMT_CL_LVL_2 | IMT_CL_LVL_2_CD | IMT_CL_LVL_3 | IMT_CL_LVL_3_CD | IMT_CL_LVL_4 | IMT_CL_LVL_4_CD | IMT_CL_LVL_5 | IMT_CL_LVL_5_CD | MODL_STRTG_DTL_AST_CLSS | MODL_STRTG_DTL_AST_CLSS_CD | MODL_STRTG_SMY_AST_CLSS | MODL_STRTG_SMY_AST_CLSS_CD | PD_DSC | PD_SHRT_NM | RPT_CL_LVL_1 | RPT_CL_LVL_2 | RPT_STRTG_DTL_AST_CLSS | RPT_STRTG_DTL_A... */
    LEFT JOIN SSDS_DAL_OWNER.FA_NUMBER_V FA_NUMBER_V_4 ON AR_GRP_SUBDIM.FA_NUM = FA_NUMBER_V_4.FA_NUMBER And TXN.TD >= FA_NUMBER_V_4.EFFECTIVE_DATE And TXN.TD < FA_NUMBER_V_4.END_DATE /* DRD_AD_RULE+CANONICAL_ALIAS+MERGED_DUP+ALIAS_DEDUP; cols=OWN_FA_NUM_TP | OWN_FA_NUM_TP_CD */
    LEFT JOIN SSDS_DAL_OWNER.CODE_SET_VALUE_V CODE_SET_VALUE_V ON CODE_SET_VALUE_V.CODE_VALUE_ID = FA_NUMBER_V.FA_NUMBER_TYPE_CODE_ID And TXN.TD >= CODE_SET_VALUE_V.EFFECTIVE_DATE And TXN.TD < CODE_SET_VALUE_V.END_DATE /* DRD_AD_RULE+CANONICAL_ALIAS; cols=OWN_FA_NUM_TP */
    LEFT JOIN CCSI_OWNER.AR_AC_SUBDIM ORIG_AR_AC_SUBDIM ON ORIG_AR_AC_SUBDIM.AR_ID = TXN.AR_ID AND ORIG_AR_AC_SUBDIM.DEP_AC_SETUP_ID = APA.AC_ID AND ORIG_AR_AC_SUBDIM.EFF_DT <= TXN.TD AND ORIG_AR_AC_SUBDIM.END_DT > TXN.TD /* AVY_CURATED_DRD_JOIN; cols=ORIG_SRC_STM_AR_ID */
    LEFT JOIN CCSI_OWNER.AR_DIM ORIG_SRC_STM_AR_DIM ON ORIG_SRC_STM_AR_DIM.AR_ID = TXN.AR_ID AND ORIG_SRC_STM_AR_DIM.EFF_DT <= TXN.TD AND ORIG_SRC_STM_AR_DIM.END_DT > TXN.TD /* AVY_CURATED_DRD_JOIN; cols=ORIG_SRC_STM_AR_ID */
    LEFT JOIN TRANSACTIONS_OWNER.LGCY_TRD_CPCTY_TP_DIM LGCY_TRD_CPCTY_TP_DIM ON TXN.LGCY_TRD_CPCTY_TP_ID = LGCY_TRD_CPCTY_TP_DIM.LGCY_TRD_CPCTY_TP_ID /* AVY_CURATED_DRD_JOIN+MERGED_DUP+MERGED_DUP+MERGED_DUP; cols=LGCY_TRD_CPCTY_TP_CD | LGCY_TRD_CPCTY_TP_DIM_ID | LGCY_TRD_CPCTY_TP_NM | ORIG_SRC_STM_AR_ID */
    LEFT JOIN CCAL_REPL_OWNER.CL_VAL LGCY_TRD_CPCTY_CL_VAL ON LGCY_TRD_CPCTY_CL_VAL.CL_VAL_ID = TXN.LGCY_TRD_CPCTY_TP_ID /* AVY_CURATED_DRD_JOIN+MERGED_DUP; cols=LGCY_TRD_CPCTY_TP_CD | LGCY_TRD_CPCTY_TP_NM */
    LEFT JOIN CCAL_REPL_OWNER.CL_VAL SDIRA_TXN_TP_CL_VAL ON SDIRA_TXN_TP_CL_VAL.CL_VAL_CODE = SUBSTR(TXN.TRD_NUM, 1, 3) AND TXN.SRC_STM_ID = 60 /* DRD_AVY_PARSE_CL_VAL_LOOKUP+MERGED_DUP; cols=SDIRA_TXN_TP | SDIRA_TXN_TP_CD */
    LEFT JOIN CCAL_REPL_OWNER.CL_VAL STEP_IN_OUT_CL_VAL ON STEP_IN_OUT_CL_VAL.CL_SCM_ID = 114 /* DRD_CL_VAL_SOURCE_RULE+MERGED_DUP; cols=STEP_IN_OUT_IND_CD | STEP_IN_OUT_IND_NM */
    LEFT JOIN CCAL_REPL_OWNER.CL_VAL SHRT_SALE_EXMPT_CD_CL_VAL ON SHRT_SALE_EXMPT_CD_CL_VAL.CL_SCM_ID = 114 /* DRD_CL_VAL_SOURCE_RULE; cols=SHRT_SALE_EXMPT_CD */
    LEFT JOIN CCAL_REPL_OWNER.CL_VAL SHRT_SALE_EXMPT_NM_CL_VAL ON SHRT_SALE_EXMPT_NM_CL_VAL.CL_SCM_ID = 115 /* DRD_CL_VAL_SOURCE_RULE; cols=SHRT_SALE_EXMPT_NM */;
